css:
.loader {
  width: 260px;
  height: 135px;
  border-radius: 14px;
  background: #ffffff;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-evenly;
  padding: 24px;
  box-shadow: 2px 2px 18px -8px #94a3b8;
}
.loading { width: 100%; height: 10px; background: #d9d9d9; border-radius: 10px; position: relative; overflow: hidden; }
.loading::after { content: ""; position: absolute; top: 0; left: 0; width: 50%; height: 10px; background: #000022; border-radius: 10px; animation: redirectBar .7s alternate infinite; }
.label { color: #000022; font-size: 18px; font-weight: 700; animation: redirectBlink .7s alternate infinite; }
@keyframes redirectBlink { from { opacity: .35; } to { opacity: 1; } }
@keyframes redirectBar { from { left: 0%; } to { left: 50%; } }
